function r(n){return btoa(encodeURIComponent(n).replace(/%([0-9A-F]{2})/g,(t,e)=>String.fromCharCode(parseInt("0x"+e,16))))}function a(n){return decodeURIComponent(atob(n).split("").map(t=>"%"+("00"+t.charCodeAt(0).toString(16)).slice(-2)).join(""))}function o(){return Math.floor(Math.random()*90+10).toString()}class c{SimpleEncode(t){const e=o()+t.toString()+o();return r(e)}SimpleDecode(t){let e=a(t);return e=e.toString(),e.substring(2,e.length-2)}}const i=new c;export{i as C};
